SELECT id, dept_id, duty_date, staff_name, staff_role, duty_time, phone, created_at
FROM medical_team_duty
WHERE id = #{id}

SELECT id, dept_id, duty_date, staff_name, staff_role, duty_time, phone, created_at
FROM medical_team_duty
WHERE dept_id = #{deptId}
  AND duty_date = #{dutyDate}
ORDER BY id
